/**
 * @summary List certificate alerts
 */
export const getGetCertAlertsUrl = (params?: GetCertAlertsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/cert-alerts?${stringifiedParams}`
    : `/api/cert-alerts`;
};

export const getCertAlerts = async (
  params?: GetCertAlertsParams,
  options?: RequestInit,
): Promise<CertAlertList> => {
  return customFetch<CertAlertList>(getGetCertAlertsUrl(params), {
    ...options,
    method: "GET",
  });
};

